function DeliveryTimesView({ rows, onUpdateStatus }) {
  const statusStyle = (status) => {
    if (status === 'Reorder Now' || status === 'Delayed') return { bg: 'rgba(193,84,60,0.1)', color: 'var(--red)' };
    if (status === 'Delivery Overdue') return { bg: 'rgba(232,163,61,0.14)', color: 'var(--amber-deep)' };
    if (status === 'In Transit' || status === 'Ordered') return { bg: 'rgba(15,42,71,0.08)', color: 'var(--blueprint)' };
    return { bg: 'rgba(79,138,99,0.1)', color: 'var(--green)' };
  };

  const handleDownload = () => {
    const headers = ['Supplier', 'SKU', 'Item', 'Lead Time (days)', 'Last Delivery', 'Expected Next', 'Status', 'Manually Set', 'Note'];
    const csvRows = rows.map(({ item, supplier, lastDelivery, expectedNext, status, manual, note }) => [
      supplier.name, item.sku, item.name, supplier.leadTimeDays, formatDate(lastDelivery), formatDate(expectedNext), status, manual ? 'Yes' : 'No', note,
    ]);
    downloadCSV('delivery-times.csv', headers, csvRows);
  };

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} />
      <div style={styles.tableWrap} className="depot-scroll">
        <table style={styles.table} className="depot-table">
          <thead>
            <tr>
              {['Supplier', 'Item', 'Lead Time', 'Last Delivery', 'Expected Next', 'Status', ''].map((h) => (
                <th key={h} style={styles.th}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rows.length === 0 && (
              <tr><td colSpan={7} style={{ ...styles.td, textAlign: 'center', padding: '32px 0', color: 'rgba(59,42,31,0.5)' }}>No items are linked to a supplier yet.</td></tr>
            )}
            {rows.map((row) => {
              const { item, supplier, lastDelivery, expectedNext, status, manual } = row;
              const st = statusStyle(status);
              return (
                <tr key={item.id} className="depot-row">
                  <td style={styles.td}>{supplier.name}</td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif" }}>{item.sku} <span style={{ fontFamily: "'Nunito', sans-serif", color: 'rgba(59,42,31,0.55)' }}>— {item.name}</span></td>
                  <td style={styles.td}>{supplier.leadTimeDays} days</td>
                  <td style={styles.td}>{formatDate(lastDelivery)}</td>
                  <td style={styles.td}>{formatDate(expectedNext)}</td>
                  <td style={styles.td}>
                    <span style={{ ...styles.statusPill, background: st.bg, color: st.color }}>
                      {status === 'On Track' && <CheckCircle2 size={12} />}
                      {status !== 'On Track' && <AlertTriangle size={12} />}
                      {status}
                    </span>
                    {manual && <span style={styles.manualBadge}>manually set</span>}
                  </td>
                  <td className="depot-no-print" style={{ ...styles.td, textAlign: 'right' }}>
                    <IconBtn onClick={() => onUpdateStatus(row)} title="Update delivery status"><Pencil size={13} /></IconBtn>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function POSView({ items, onCompleteSale }) {
  const [search, setSearch] = useState('');
  const [cart, setCart] = useState([]); // [{itemId, qty}]
  const [paymentMethod, setPaymentMethod] = useState(PAYMENT_METHODS[0]);
  const [lastReceipt, setLastReceipt] = useState(null);

  const sellable = useMemo(() => items.filter((it) => it.quantity > 0), [items]);
  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return sellable.filter((it) => it.sku.toLowerCase().includes(q) || it.name.toLowerCase().includes(q));
  }, [sellable, search]);

  const itemMap = useMemo(() => Object.fromEntries(items.map((i) => [i.id, i])), [items]);

  const addToCart = (item) => {
    setLastReceipt(null);
    setCart((prev) => {
      const existing = prev.find((l) => l.itemId === item.id);
      if (existing) {
        if (existing.qty >= item.quantity) return prev;
        return prev.map((l) => (l.itemId === item.id ? { ...l, qty: l.qty + 1 } : l));
      }
      return [...prev, { itemId: item.id, qty: 1 }];
    });
  };

  const changeQty = (itemId, delta) => {
    setCart((prev) => prev
      .map((l) => {
        if (l.itemId !== itemId) return l;
        const max = itemMap[itemId]?.quantity ?? l.qty;
        const nextQty = Math.min(max, Math.max(1, l.qty + delta));
        return { ...l, qty: nextQty };
      })
    );
  };

  const removeLine = (itemId) => setCart((prev) => prev.filter((l) => l.itemId !== itemId));

  const subtotal = cart.reduce((s, l) => s + (itemMap[l.itemId]?.unitCost ?? 0) * l.qty, 0);
  const tax = subtotal * TAX_RATE;
  const total = subtotal + tax;

  const [busy, setBusy] = useState(false);

  const checkout = async () => {
    setBusy(true);
    try {
      const sale = await onCompleteSale(cart, paymentMethod);
      if (sale) {
        setLastReceipt(sale);
        setCart([]);
      }
    } finally {
      setBusy(false);
    }
  };

  return (
    <div style={{ animation: 'fadeIn 0.3s ease', display: 'grid', gridTemplateColumns: '1.4fr 1fr', gap: 16, alignItems: 'start' }} className="depot-pos-layout">
      <div>
        <div style={styles.searchBox}>
          <Search size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="Search items to sell…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.searchInput}
          />
        </div>
        <div style={styles.posGrid} className="depot-pos-grid">
          {filtered.length === 0 && (
            <div style={styles.emptyState}>No sellable items match your search.</div>
          )}
          {filtered.map((it) => (
            <button key={it.id} className="depot-btn" style={styles.posItemCard} onClick={() => addToCart(it)}>
              <div style={styles.posItemSku}>{it.sku}</div>
              <div style={styles.posItemName}>{it.name}</div>
              <div style={styles.posItemFooter}>
                <span>{currency(it.unitCost)}</span>
                <span style={{ color: 'rgba(59,42,31,0.5)' }}>{it.quantity} in stock</span>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div style={styles.cartPanel} className="depot-cart-panel">
        <div style={styles.panelHeader}>
          <ShoppingCart size={15} />
          <span>CURRENT SALE</span>
        </div>

        {cart.length === 0 ? (
          <div style={styles.emptyState}>Tap an item to add it to the sale.</div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10 }}>
            {cart.map((line) => {
              const item = itemMap[line.itemId];
              if (!item) return null;
              return (
                <div key={line.itemId} style={styles.cartLine}>
                  <div style={{ flex: 1 }}>
                    <div style={styles.watchSku}>{item.sku}</div>
                    <div style={styles.watchName}>{item.name}</div>
                  </div>
                  <div style={styles.qtyStepper}>
                    <button className="depot-btn" style={styles.qtyBtn} onClick={() => changeQty(line.itemId, -1)}><Minus size={12} /></button>
                    <span style={styles.qtyValue}>{line.qty}</span>
                    <button className="depot-btn" style={styles.qtyBtn} onClick={() => changeQty(line.itemId, 1)}><Plus size={12} /></button>
                  </div>
                  <div style={{ width: 72, textAlign: 'right', fontFamily: "'Quicksand', sans-serif", fontSize: 12.5 }}>
                    {currency(item.unitCost * line.qty)}
                  </div>
                  <IconBtn onClick={() => removeLine(line.itemId)} title="Remove" danger><X size={13} /></IconBtn>
                </div>
              );
            })}
          </div>
        )}

        <div style={styles.cartTotals}>
          <div style={styles.cartTotalsRow}><span>Subtotal</span><span>{currency(subtotal)}</span></div>
          <div style={styles.cartTotalsRow}><span>VAT (12%)</span><span>{currency(tax)}</span></div>
          <div style={{ ...styles.cartTotalsRow, ...styles.cartTotalsFinal }}><span>Total</span><span>{currency(total)}</span></div>
        </div>

        <div style={{ display: 'flex', gap: 6, marginTop: 12 }}>
          {PAYMENT_METHODS.map((m) => (
            <button key={m} className="depot-btn" onClick={() => setPaymentMethod(m)}
              style={{ ...styles.paymentBtn, background: paymentMethod === m ? 'var(--blueprint)' : 'transparent', color: paymentMethod === m ? '#fff' : 'var(--ink)' }}>
              {m}
            </button>
          ))}
        </div>

        <button className="depot-btn" style={{ ...styles.primaryBtn, width: '100%', justifyContent: 'center', marginTop: 12, opacity: cart.length && !busy ? 1 : 0.45 }}
          disabled={!cart.length || busy} onClick={checkout}>
          <Receipt size={16} /> {busy ? 'Processing…' : 'Complete Sale'}
        </button>
      </div>

      {lastReceipt && (
        <SaleReceiptModal sale={lastReceipt} onClose={() => setLastReceipt(null)} />
      )}
    </div>
  );
}

function SalesHistoryView({ sales, role, onCancelSale }) {
  const canCancel = can(role, 'cancelSales');
  const [cashierFilter, setCashierFilter] = useState('All');
  const [expandedId, setExpandedId] = useState(null);

  const cashiers = useMemo(() => {
    const set = new Set(sales.map((s) => s.cashierEmail).filter(Boolean));
    return Array.from(set).sort();
  }, [sales]);

  const filtered = useMemo(() => {
    if (cashierFilter === 'All') return sales;
    return sales.filter((s) => s.cashierEmail === cashierFilter);
  }, [sales, cashierFilter]);

  const overall = useMemo(() => {
    const active = sales.filter((s) => !s.cancelled);
    return { count: active.length, total: active.reduce((sum, s) => sum + s.total, 0) };
  }, [sales]);

  const byCashier = useMemo(() => {
    const map = {};
    sales.forEach((s) => {
      if (s.cancelled) return;
      const key = s.cashierEmail || 'Unknown';
      if (!map[key]) map[key] = { count: 0, total: 0 };
      map[key].count += 1;
      map[key].total += s.total;
    });
    return Object.entries(map)
      .map(([email, v]) => ({ email, ...v }))
      .sort((a, b) => b.total - a.total);
  }, [sales]);

  const handleDownload = () => {
    const headers = ['Receipt', 'Date', 'Cashier', 'Items', 'Payment Method', 'Subtotal', 'VAT', 'Total', 'Status'];
    const rows = filtered.map((sale) => [
      sale.receiptNo,
      new Date(sale.timestamp).toLocaleString('en-PH'),
      sale.cashierEmail || '—',
      sale.items.map((l) => `${l.qty}x ${l.sku}`).join('; '),
      sale.paymentMethod,
      sale.subtotal.toFixed(2),
      sale.tax.toFixed(2),
      sale.total.toFixed(2),
      sale.cancelled ? 'Cancelled' : 'Completed',
    ]);
    downloadCSV('sales-history.csv', headers, rows);
  };

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} />

      <div style={styles.statGrid} className="depot-stat-grid">
        <StatCard icon={Receipt} label="Sales (Overall)" value={overall.count} accent="var(--blueprint)" />
        <StatCard icon={PesoIcon} label="Total Revenue (Overall)" value={currency(overall.total)} accent="var(--green)" />
      </div>

      {byCashier.length > 0 && (
        <div style={{ ...styles.panel, marginBottom: 16 }}>
          <div style={styles.panelHeader}>
            <User size={15} />
            <span>TOTAL SALES PER ACCOUNT</span>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10 }}>
            {byCashier.map((c) => (
              <div key={c.email} style={styles.watchRow}>
                <div>
                  <div style={styles.watchSku}>{c.email}</div>
                  <div style={styles.watchName}>{c.count} sale{c.count === 1 ? '' : 's'}</div>
                </div>
                <div style={{ fontWeight: 700, fontFamily: "'Quicksand', sans-serif", color: 'var(--ink)' }}>
                  {currency(c.total)}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {cashiers.length > 0 && (
        <div style={styles.filterBar} className="depot-no-print depot-filterbar">
          <select className="depot-select" value={cashierFilter} onChange={(e) => setCashierFilter(e.target.value)} style={styles.select}>
            <option value="All">All Staff</option>
            {cashiers.map((c) => <option key={c} value={c}>{c}</option>)}
          </select>
          {cashierFilter !== 'All' && (
            <div style={{ ...styles.watchName, alignSelf: 'center' }}>
              {filtered.length} sale{filtered.length === 1 ? '' : 's'} · {currency(filtered.reduce((s, x) => s + (x.cancelled ? 0 : x.total), 0))} total
            </div>
          )}
        </div>
      )}
      {filtered.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No sales recorded yet. Ring one up in Point of Sale.</div></div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['Receipt', 'Date', 'Cashier', 'Items', 'Payment', 'Total', 'Status', ...(canCancel ? [''] : [])].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((sale) => {
                const isOpen = expandedId === sale.id;
                const colCount = 7 + (canCancel ? 1 : 0);
                return (
                <React.Fragment key={sale.id}>
                <tr className="depot-row" style={sale.cancelled ? { opacity: 0.55 } : undefined}>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500, textDecoration: sale.cancelled ? 'line-through' : 'none' }}>{sale.receiptNo}</td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontSize: 12.5 }}>
                    {new Date(sale.timestamp).toLocaleString('en-PH', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                  </td>
                  <td style={{ ...styles.td, fontSize: 12.5 }}>{sale.cashierEmail || '—'}</td>
                  <td style={styles.td}>
                    <button
                      className="depot-btn"
                      onClick={() => setExpandedId(isOpen ? null : sale.id)}
                      style={{
                        display: 'flex', alignItems: 'center', gap: 5, background: 'transparent',
                        border: 'none', padding: 0, color: 'var(--blueprint)', fontSize: 13, fontFamily: "'Nunito', sans-serif",
                      }}
                    >
                      <ChevronDown size={14} className="depot-no-print" style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform 0.15s ease' }} />
                      {sale.items.length} item{sale.items.length === 1 ? '' : 's'}
                    </button>
                  </td>
                  <td style={styles.td}><span style={styles.pill}>{sale.paymentMethod}</span></td>
                  <td style={{ ...styles.td, fontWeight: 600, textDecoration: sale.cancelled ? 'line-through' : 'none' }}>{currency(sale.total)}</td>
                  <td style={styles.td}>
                    {sale.cancelled ? (
                      <span style={{ ...styles.statusPill, background: 'rgba(193,80,58,0.1)', color: 'var(--red)' }}>Cancelled</span>
                    ) : (
                      <span style={{ ...styles.statusPill, background: 'rgba(79,138,99,0.1)', color: 'var(--green)' }}>Completed</span>
                    )}
                  </td>
                  {canCancel && (
                    <td className="depot-no-print" style={{ ...styles.td, textAlign: 'right' }}>
                      {!sale.cancelled && (
                        <button className="depot-btn" style={{ ...styles.smallAmberBtn, background: 'transparent', color: 'var(--red)', border: '1px solid rgba(193,80,58,0.3)' }} onClick={() => onCancelSale(sale)}>
                          Cancel
                        </button>
                      )}
                    </td>
                  )}
                </tr>
                {isOpen && (
                  <tr className="depot-row">
                    <td colSpan={colCount} style={{ ...styles.td, background: 'rgba(20,33,61,0.02)', padding: '10px 14px' }}>
                      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                        <thead>
                          <tr>
                            {['SKU', 'Item', 'Qty', 'Unit Price', 'Line Total'].map((h) => (
                              <th key={h} style={{ ...styles.th, padding: '4px 8px', fontSize: 10.5 }}>{h}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {sale.items.map((l, i) => (
                            <tr key={i}>
                              <td style={{ padding: '4px 8px', fontFamily: "'Quicksand', sans-serif", fontSize: 12 }}>{l.sku}</td>
                              <td style={{ padding: '4px 8px', fontSize: 12 }}>{l.name}</td>
                              <td style={{ padding: '4px 8px', fontSize: 12 }}>{l.qty}</td>
                              <td style={{ padding: '4px 8px', fontSize: 12, fontFamily: "'IBM Plex Mono', monospace" }}>{currency(l.unitPrice)}</td>
                              <td style={{ padding: '4px 8px', fontSize: 12, fontFamily: "'IBM Plex Mono', monospace", fontWeight: 600 }}>{currency(l.lineTotal)}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </td>
                  </tr>
                )}
                </React.Fragment>
                );
              })}
            </tbody>

          </table>
        </div>
      )}
    </div>
  );
}

function MySalesView({ sales }) {
  const totalToday = useMemo(() => {
    const start = new Date(); start.setHours(0, 0, 0, 0);
    return sales.filter((s) => !s.cancelled && s.timestamp >= start.getTime()).reduce((s, x) => s + x.total, 0);
  }, [sales]);
  const totalAll = useMemo(() => sales.filter((s) => !s.cancelled).reduce((s, x) => s + x.total, 0), [sales]);

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <div style={styles.statGrid} className="depot-stat-grid">
        <StatCard icon={Receipt} label="Sales Recorded" value={sales.length} accent="var(--blueprint)" />
        <StatCard icon={PesoIcon} label="Total Today" value={currency(totalToday)} accent="var(--green)" />
        <StatCard icon={PesoIcon} label="Total All-Time" value={currency(totalAll)} accent="var(--amber-deep)" />
      </div>
      {sales.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>You haven't processed any sales yet. Ring one up in Point of Sale.</div></div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['Receipt', 'Date', 'Items', 'Payment', 'Total', 'Status'].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {sales.map((sale) => (
                <tr key={sale.id} className="depot-row" style={sale.cancelled ? { opacity: 0.55 } : undefined}>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500, textDecoration: sale.cancelled ? 'line-through' : 'none' }}>{sale.receiptNo}</td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontSize: 12.5 }}>
                    {new Date(sale.timestamp).toLocaleString('en-PH', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                  </td>
                  <td style={styles.td}>{sale.items.map((l) => `${l.qty}× ${l.sku}`).join(', ')}</td>
                  <td style={styles.td}><span style={styles.pill}>{sale.paymentMethod}</span></td>
                  <td style={{ ...styles.td, fontWeight: 600, textDecoration: sale.cancelled ? 'line-through' : 'none' }}>{currency(sale.total)}</td>
                  <td style={styles.td}>
                    {sale.cancelled ? (
                      <span style={{ ...styles.statusPill, background: 'rgba(193,80,58,0.1)', color: 'var(--red)' }}>Cancelled</span>
                    ) : (
                      <span style={{ ...styles.statusPill, background: 'rgba(79,138,99,0.1)', color: 'var(--green)' }}>Completed</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function ActivityLogView({ logs, myRole, approvedUsers, pendingUsers }) {
  const [userFilter, setUserFilter] = useState('All');
  const roleByUid = useMemo(() => {
    const map = {};
    [...approvedUsers, ...pendingUsers].forEach((u) => { map[u.id] = u.role; });
    return map;
  }, [approvedUsers, pendingUsers]);

  const users = useMemo(() => {
    const set = new Set(logs.map((l) => l.email).filter(Boolean));
    return Array.from(set).sort();
  }, [logs]);

  const filtered = userFilter === 'All' ? logs : logs.filter((l) => l.email === userFilter);

  const handleDownload = () => {
    const headers = ['Email', 'Role', 'Type', 'Timestamp'];
    const rows = filtered.map((l) => [l.email, ROLES[roleByUid[l.uid]] || '—', l.type, new Date(l.timestamp).toLocaleString('en-PH')]);
    downloadCSV('activity-log.csv', headers, rows);
  };

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} />
      {users.length > 0 && (
        <div style={styles.filterBar} className="depot-no-print depot-filterbar">
          <select className="depot-select" value={userFilter} onChange={(e) => setUserFilter(e.target.value)} style={styles.select}>
            <option value="All">All Users</option>
            {users.map((u) => <option key={u} value={u}>{u}</option>)}
          </select>
        </div>
      )}
      {filtered.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No activity recorded yet.</div></div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['Email', 'Role', 'Event', 'Timestamp'].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((l) => (
                <tr key={l.id} className="depot-row">
                  <td style={styles.td}>{l.email}</td>
                  <td style={styles.td}><span style={styles.pill}>{ROLES[roleByUid[l.uid]] || '—'}</span></td>
                  <td style={styles.td}>
                    {l.type === 'login' ? (
                      <span style={{ ...styles.statusPill, background: 'rgba(79,138,99,0.1)', color: 'var(--green)' }}>Login</span>
                    ) : (
                      <span style={{ ...styles.statusPill, background: 'rgba(20,33,61,0.08)', color: 'var(--ink)' }}>Logout</span>
                    )}
                  </td>
                  <td style={{ ...styles.td, fontFamily: "'IBM Plex Mono', monospace", fontSize: 12.5 }}>
                    {new Date(l.timestamp).toLocaleString('en-PH', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function ProfileEditModal({ user, onClose, onSave }) {
  const [fullName, setFullName] = useState(user.fullName || '');
  const [username, setUsername] = useState(user.username || '');
  const [contactNumber, setContactNumber] = useState(user.contactNumber || '');
  const [address, setAddress] = useState(user.address || '');

  const submit = () => {
    onSave(user.id, { fullName, username, contactNumber, address });
    onClose();
  };

  return (
    <div style={styles.overlay} onClick={onClose}>
      <div style={{ ...styles.modal, maxWidth: 400 }} className="depot-modal" onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHeader}>
          <span>EDIT PROFILE — {user.email}</span>
          <button className="depot-btn" onClick={onClose} style={styles.closeBtn}><X size={16} /></button>
        </div>
        <div style={styles.modalBody}>
          <div style={{ fontSize: 11.5, color: 'rgba(59,42,31,0.5)', marginBottom: 14, fontFamily: "'IBM Plex Mono', monospace" }}>
            ID: {user.userIdNumber || '—'} · Account: {user.id}
          </div>
          <Field label="Full Name">
            <input className="depot-input" style={styles.modalInput} value={fullName} onChange={(e) => setFullName(e.target.value)} />
          </Field>
          <Field label="Username">
            <input className="depot-input" style={styles.modalInput} value={username} onChange={(e) => setUsername(e.target.value)} />
          </Field>
          <Field label="Contact Number">
            <input className="depot-input" style={styles.modalInput} value={contactNumber} onChange={(e) => setContactNumber(e.target.value)} />
          </Field>
          <Field label="Address">
            <input className="depot-input" style={styles.modalInput} value={address} onChange={(e) => setAddress(e.target.value)} />
          </Field>
        </div>
        <div style={styles.modalFooter}>
          <button className="depot-btn" style={styles.ghostBtn} onClick={onClose}>Cancel</button>
          <button className="depot-btn" style={styles.primaryBtn} onClick={submit}>Save</button>
        </div>
      </div>
    </div>
  );
}

